import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"火神庙","description":"","frontmatter":{},"headers":[],"relativePath":"religion/huoshen.md","filePath":"religion/huoshen.md","lastUpdated":1784712887000}'),n={name:"religion/huoshen.md"};function i(o,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="火神庙" tabindex="-1">火神庙 <a class="header-anchor" href="#火神庙" aria-label="Permalink to &quot;火神庙&quot;">​</a></h1><blockquote><p>&quot;什刹海边的千年古庙，火神庇佑之地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>火神庙位于北京市西城区什刹海边，是北京历史最悠久的火神庙。火神庙始建于唐贞观六年（632年），距今已有1400余年历史。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线什刹海站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区地安门外大街77号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>火神庙始建于唐贞观六年（632年），是北京最早的火神庙。</p><h3 id="历代修缮" tabindex="-1">历代修缮 <a class="header-anchor" href="#历代修缮" aria-label="Permalink to &quot;历代修缮&quot;">​</a></h3><ul><li><strong>元代</strong>：元世祖忽必烈曾到此进香</li><li><strong>明代</strong>：明万历年间重修</li><li><strong>清代</strong>：清乾隆年间重修，规模扩大</li><li><strong>现代</strong>：2008年修复后对外开放</li></ul><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是火神庙的入口。</p><h3 id="灵官殿" tabindex="-1">灵官殿 <a class="header-anchor" href="#灵官殿" aria-label="Permalink to &quot;灵官殿&quot;">​</a></h3><p>灵官殿供奉道教护法神王灵官。</p><h3 id="火神殿" tabindex="-1">火神殿 <a class="header-anchor" href="#火神殿" aria-label="Permalink to &quot;火神殿&quot;">​</a></h3><p>火神殿是火神庙的主殿，供奉火神。</p><h4 id="火神" tabindex="-1">火神 <a class="header-anchor" href="#火神" aria-label="Permalink to &quot;火神&quot;">​</a></h4><p>火神是道教尊神，掌管火，是民间信仰的重要神祇。</p><h3 id="慈航殿" tabindex="-1">慈航殿 <a class="header-anchor" href="#慈航殿" aria-label="Permalink to &quot;慈航殿&quot;">​</a></h3><p>慈航殿供奉慈航道人（观音菩萨的道教化身）。</p><h3 id="真武殿" tabindex="-1">真武殿 <a class="header-anchor" href="#真武殿" aria-label="Permalink to &quot;真武殿&quot;">​</a></h3><p>真武殿供奉真武大帝。</p><h2 id="什刹海" tabindex="-1">什刹海 <a class="header-anchor" href="#什刹海" aria-label="Permalink to &quot;什刹海&quot;">​</a></h2><p>火神庙位于什刹海边，可以欣赏什刹海的美景。</p><h3 id="什刹海-1" tabindex="-1">什刹海 <a class="header-anchor" href="#什刹海-1" aria-label="Permalink to &quot;什刹海&quot;">​</a></h3><p>什刹海是北京著名的风景区，由前海、后海、西海组成。</p><h3 id="荷花市场" tabindex="-1">荷花市场 <a class="header-anchor" href="#荷花市场" aria-label="Permalink to &quot;荷花市场&quot;">​</a></h3><p>夏季，什刹海有荷花市场，非常热闹。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>寺庙参观（约30分钟）</strong>：</p><p>山门 → 灵官殿 → 火神殿 → 慈航殿 → 真武殿 → 出庙</p><p><strong>结合什刹海路线</strong>：</p><p>火神庙 → 什刹海 → 银锭桥 → 烟袋斜街 → 钟鼓楼</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">8号线什刹海站A2口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">5路、60路、82路等地安门内站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从北海公园步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费参观</strong>：免费开放</li><li><strong>什刹海风光</strong>：可以欣赏什刹海</li><li><strong>人少清静</strong>：游客较少</li><li><strong>结合游览</strong>：可与什刹海、钟鼓楼一起游览</li><li><strong>夏季荷花</strong>：夏季什刹海荷花盛开</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">老北京风情</td></tr><tr><td style="text-align:left;">银锭桥</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">什刹海标志性建筑</td></tr><tr><td style="text-align:left;">烟袋斜街</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">特色商业街</td></tr><tr><td style="text-align:left;">钟鼓楼</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">古代报时中心</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>火神庙是北京历史最悠久的火神庙，距今已有1400余年历史。</p><p>火神庙位于什刹海边，是北京民俗信仰的重要场所。</p><p>火神庙是北京中轴线的重要组成部分。</p><hr><p><strong>📍 地址</strong>：北京市西城区地安门外大街77号</p>',48)])])}const f=e(n,[["render",i]]);export{c as __pageData,f as default};
